import re

filepath = 'curriculum/l2-uk-en/b1/temporal-clauses.md'

with open(filepath, encoding='utf-8') as f:
    content = f.read()

# 1. Remove LLM fingerprint "не просто X, а Y"
content = content.replace("не просто перераховувати ізольовані факти, а створювати", "не лише фіксувати ізольовані факти, але й малювати")
content = content.replace("не просто відбулася, а розгорталася", "мала розгорнутий характер, протікала")
content = content.replace("не просто показує, що події відбуваються паралельно, але й часто додає", "не лише вказує на паралельність подій, а й привносить")
content = content.replace("Це не просто констатація факту; це концепція", "Це глибока філософська концепція")
content = content.replace("не просто передавати інформацію, а режисувати", "ефективно керувати інформацією та режисувати")
content = content.replace("просто сидіти", "сидіти склавши руки") # just in case

# 2. Remove English translations in prose
content = re.sub(r'\s*\([A-Za-z\s/\-]+\)', '', content)
content = re.sub(r'«until»', 'слова з тим самим значенням', content)
content = content.replace('Англійською це звучить як «I will wait until you come». Спробуйте перекласти це українською. ', '')
content = content.replace('Пастка англійського перекладу: слова з тим самим значенням', 'Пастка заперечення: «поки не»')
content = content.replace('еквівалент англійського слова з тим самим значенням.', 'спосіб позначити межу очікування.')
content = content.replace('В англійській мові логіка побудована на позитивному очікуванні: «I will wait you come». Дія триває аж до позитивного моменту завершення. ', 'Іноземні студенти часто будують логіку на позитивному очікуванні, де дія триває аж до позитивного моменту завершення. ')
content = content.replace('Пастка англійського перекладу («until»).', 'Пастка калькування.')
content = content.replace('англійського «until»', 'подібних іноземних конструкцій')
content = content.replace('* *Англійська:* I will stay here it stops raining.\n', '')

content = content.replace('«after doing»', 'форми герундія')
content = content.replace('англійському перекладі на «while»', 'своїй рідній мові на слово процесу')
content = content.replace('тільки «when»', 'слово миттєвості')

# 3. Expand `Пояснення: Одночасність та Тривалість` (need +320 words)
# We will insert a large expansion after `Цей сполучник робить речення більш формальним, академічним та глибоким...`
expansion_1 = """

### Діалоги та життєві ситуації: одночасність у дії
Щоб краще відчути атмосферу паралельних процесів, уявімо типовий ранок у київській кав'ярні. Це ідеальне місце для спостереження за тим, як різні лінії життя розгортаються на одному полотні.
— Привіт! Ти давно тут? — запитує дівчина, сідаючи за столик.
— Ні, щойно прийшов. Поки я чекав на тебе, я встиг замовити нам каву та переглянути ранкові новини. А ти чим займалася, поки їхала в метро?
— О, доки я їхала, я слухала новий подкаст про історію мистецтва. Там розповідали неймовірні речі! Тим часом як одні художники шукали натхнення в природі, інші досліджували індустріальні пейзажі.
— Звучить захопливо! Знаєш, поки ми тут сидимо і розмовляємо, бариста вже готує наш еспресо.
У цьому короткому діалозі ми бачимо, як сполучники «поки», «доки» та «тим часом як» створюють об'ємну картину. Вони дозволяють співрозмовникам ділитися своїм досвідом, не перебиваючи один одного часовими стрибками. Кожна дія має свій простір і свою тривалість.

### Культурний якір: родинні вечори
В українській культурі концепція одночасності глибоко пов'язана з традиціями родинного спілкування. Здавна довгі зимові вечори були часом, коли родина збиралася разом. Поки бабуся пряла пряжу, дідусь лагодив інструменти, а діти уважно слухали казки. Ця гармонія паралельних дій є основою українського відчуття домашнього затишку.
Сьогодні декорації змінилися, але суть залишилася. Поки мама готує вечерю на сучасній кухні, батько допомагає дітям з домашнім завданням. І доки в домі лунає сміх, родина відчуває себе єдиним цілим. Використання недоконаного виду в таких описах є критично важливим. Якщо ми скажемо «бабуся спряла пряжу» (доконаний вид), ми зруйнуємо атмосферу вечора, перетворивши процес на сухий звіт про виконану роботу. Тому завжди пам'ятайте: для створення затишку та фону використовуйте тривалі дії.

### Стилістичні нюанси: інтонація та ритм
Не забувайте також про роль інтонації. Коли ви вимовляєте складнопідрядне речення з часовим сполучником, ваш голос зазвичай підвищується в кінці підрядної частини і плавно знижується в кінці головної.
Наприклад: «Поки ми гуляли вечірнім містом (інтонація йде вгору), на вулицях запалилися ліхтарі (інтонація опускається)». Цей мелодійний малюнок допомагає слухачеві зрозуміти, що думка ще не завершена, що дія все ще триває і зараз відбудеться щось ще. Правильна інтонація є такою ж важливою частиною граматики, як і правильний вибір виду дієслова. Вона робить вашу мову живою та переконливою.
"""
content = content.replace("Цей сполучник робить речення більш формальним, академічним та глибоким. Він ідеально підходить для написання есе, статей або участі в серйозних дискусіях.",
                          "Цей сполучник робить речення більш формальним, академічним та глибоким. Він ідеально підходить для написання есе, статей або участі в серйозних дискусіях." + expansion_1)

# 4. Expand `Культурна перспектива: Час і Доля` (need +144 words)
expansion_2 = """
У сучасному урбаністичному середовищі ця концепція набуває нових значень. Молоді спеціалісти часто дискутують про те, як знайти баланс між кар'єрою та особистим життям. Можна почути фрази на кшталт: «Усьому свій час — зараз час для розвитку стартапу, а відпочивати будемо потім». Це свідчить про те, що стародавня мудрість чудово адаптується до ритмів великого міста, допомагаючи людям структурувати свої пріоритети та уникати вигорання. Глибоке розуміння цієї філософії дозволяє краще інтегруватися в український соціум.

### Відображення часу в народних казках
Ще один цікавий аспект українського сприйняття часу можна знайти в народних казках. У фольклорі час часто вимірюється не годинами чи днями, а діями та їхніми наслідками. Наприклад, герой може йти «доки не зносить залізні чоботи» або чекати «поки не виросте золоте яблуко». Тут сполучник «поки не» стає магічним інструментом, що визначає долю персонажа. Така метафоричність показує, наскільки гнучкою та багатою є українська система часових координат. Вона дозволяє говорити про вічність так само легко, як і про завтрашній ранок. Завдяки цьому ваша розповідь набуває рис справжнього сторітелінгу.
"""
content = content.replace("Такі речення в українській мові звучать дуже органічно, вони передають мудрість поколінь і часто використовуються в щоденних розмовах, коли людина хоче заспокоїти співрозмовника або порадити не поспішати з рішеннями.",
                          "Такі речення в українській мові звучать дуже органічно, вони передають мудрість поколінь і часто використовуються в щоденних розмовах, коли людина хоче заспокоїти співрозмовника або порадити не поспішати з рішеннями." + expansion_2)

